import React, { useEffect } from 'react';
import * as C from './style';
/* import {
    FaRegArrowAltCircleUp,
    FaRegArrowAltCircleDown,
    FaTrash,
} from 'react-icons/fa'; */

function BoxPedido({ pedido, produtos }) {

    useEffect( () => {
        let text = pedido.carrinho.typeOf()
        if(text === "String") pedido.carrinho = JSON.parse(pedido.carrinho)
    }, [])


    return (
        <C.Item>
            <C.Nome>
                <C.PontoCarne>
                    <p>
                        {pedido.carrinho.pontoCarne}
                    </p>
                </C.PontoCarne>
                <p>
                    {pedido.qtd}{pedido.carnes >= 2 ? 'x'+pedido.carnes : ''} {pedido.nome}
                </p>
            </C.Nome>
{/*             <C.BoxAdc qtdAdc={null}>
                {pedido.carrinho.adc.map( (e, index) => {
                    e !== '' && (<C.Adc key={index}>{'+' + e}</C.Adc>)})}
            </C.BoxAdc> */}
            <C.Obs>
                <p>{pedido.obs}</p>
            </C.Obs>
        </C.Item>
    )
}

export default BoxPedido
